import Section from "./components/Section/Section";

function Home() {
  return (
    <>
      {/* other components: Navbar, Hero, Search, etc. */}

      <Section
        title="Top Albums"
        endpoint="https://qtify-backend.labs.crio.do/albums/top"
      />

      <Section
        title="New Albums"
        endpoint="https://qtify-backend.labs.crio.do/albums/new"
      />

      {/* Songs section: data from /songs, likes instead of follows, no Show All */}
      <Section
        title="Songs"
        endpoint="https://qtify-backend.labs.crio.do/songs"
        isSongsSection={true}
        showToggle={false}
      />
    </>
  );
}

export default Home;
